Javascript.validate:
var val = Services.getValue(SuretySum1.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(SuretySum1.dataBinding, WPU.formatToTwoDP(val));
}
return err;

Javascript.miscCode:
function DefaultCurrency557() {}
DefaultCurrency557.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency557.tabIndex = -1;
DefaultCurrency557.maxLength = 1;
DefaultCurrency557.isReadOnly = function(){return true;}
DefaultCurrency557.isTemporary = function(){return true;}
DefaultCurrency557.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency557.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
